class S3Service {
  final String _accessKey = dotenv.env['AWS_ACCESS_KEY'] ?? '';
  final String _secretKey = dotenv.env['AWS_SECRET_KEY'] ?? '';
  final String _bucket = dotenv.env['AWS_S3_BUCKET'] ?? '';
  final String _region = dotenv.env['AWS_REGION'] ?? 'us-east-1';

  Future<String> uploadFile(File file) async {
    if (_accessKey.isEmpty || _secretKey.isEmpty || _bucket.isEmpty) {
      throw Exception('AWS credentials not configured. Please set up .env file.');
    }

    final fileName = '${DateTime.now().millisecondsSinceEpoch}_${file.path.split('/').last}';
    final bytes = await file.readAsBytes();
    final contentType = 'image/jpeg';

    final url = 'https://$_bucket.s3.$_region.amazonaws.com/$fileName';
    final date = HttpDate.format(DateTime.now().toUtc());

    final canonicalRequest = _buildCanonicalRequest(
      'PUT',
      '/$fileName',
      '',
      {
        'host': '$_bucket.s3.$_region.amazonaws.com',
        'x-amz-date': date,
        'x-amz-content-sha256': sha256.convert(bytes).toString(),
      },
      sha256.convert(bytes).toString(),
    );

    final stringToSign = _buildStringToSign(
      date,
      _region,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    );

    final signature = _calculateSignature(stringToSign, date, _region);

    final response = await http.put(
      Uri.parse(url),
      headers: {
        'Host': '$_bucket.s3.$_region.amazonaws.com',
        'x-amz-date': date,
        'x-amz-content-sha256': sha256.convert(bytes).toString(),
        'Authorization': _buildAuthorizationHeader(date, _region, signature),
        'Content-Type': contentType,
      },
      body: bytes,
    );

    if (response.statusCode == 200) {
      return url;
    } else {
      throw Exception('Failed to upload to S3: ${response.statusCode} ${response.body}');
    }
  }

  String _buildCanonicalRequest(String method, String path, String query,
      Map<String, String> headers, String payloadHash) {
    final sortedHeaders = headers.keys.toList()..sort();
    final canonicalHeaders =
        sortedHeaders.map((key) => '${key.toLowerCase()}:${headers[key]}').join('\n');
    final signedHeaders = sortedHeaders.map((key) => key.toLowerCase()).join(';');

    return '$method\n$path\n$query\n$canonicalHeaders\n\n$signedHeaders\n$payloadHash';
  }

  String _buildStringToSign(String date, String region, String canonicalRequestHash) {
    final dateStamp = date.substring(0, 8);
    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    return 'AWS4-HMAC-SHA256\n$date\n$credentialScope\n$canonicalRequestHash';
  }

  String _calculateSignature(String stringToSign, String date, String region) {
    final dateStamp = date.substring(0, 8);
    final kDate = _hmacSha256(utf8.encode('AWS4$_secretKey'), utf8.encode(dateStamp));
    final kRegion = _hmacSha256(kDate, utf8.encode(region));
    final kService = _hmacSha256(kRegion, utf8.encode('s3'));
    final kSigning = _hmacSha256(kService, utf8.encode('aws4_request'));
    final signature = _hmacSha256(kSigning, utf8.encode(stringToSign));
    return signature.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
  }

  List<int> _hmacSha256(List<int> key, List<int> data) {
    final hmac = Hmac(sha256, key);
    return hmac.convert(data).bytes;
  }

  String _buildAuthorizationHeader(String date, String region, String signature) {
    final dateStamp = date.substring(0, 8);
    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    return 'AWS4-HMAC-SHA256 Credential=$_accessKey/$credentialScope, SignedHeaders=host;x-amz-content-sha256;x-amz-date, Signature=$signature';
  }
}

class VisionService {
  final String _apiKey = dotenv.env['GOOGLE_CLOUD_API_KEY'] ?? '';

  Future<Map<String, dynamic>> analyzeImage(File imageFile) async {
    if (_apiKey.isEmpty) {
      throw Exception('Google Cloud API key not configured. Please set up .env file.');
    }

    final bytes = await imageFile.readAsBytes();
    final base64Image = base64Encode(bytes);

    final url = 'https://vision.googleapis.com/v1/images:annotate?key=$_apiKey';

    final requestBody = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'FACE_DETECTION'},
            {'type': 'TEXT_DETECTION'},
          ]
        }
      ]
    };

    final response = await http.post(
      Uri.parse(url),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(requestBody),
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      final annotations = data['responses'][0];

      return {
        'labels': annotations['labelAnnotations'] ?? [],
        'faces': annotations['faceAnnotations'] ?? [],
        'text': annotations['textAnnotations'] ?? [],
      };
    } else {
      throw Exception('Failed to analyze image: ${response.statusCode} ${response.body}');
    }
  }
}